package minesweeper.service;

import minesweeper.model.EmailVerificationToken;
import minesweeper.model.enums.Role;
import minesweeper.model.User;
import minesweeper.repository.EmailVerificationRepository;
import minesweeper.repository.MySqlEmailVerificationRepository;
import minesweeper.repository.exception.DataAccessException;
import utils.CryptUtils;

import jakarta.mail.MessagingException;
import java.security.SecureRandom;
import java.time.LocalDateTime;

public class AuthService {

    private static final int OTP_LENGTH      = 6;
    private static final int OTP_EXPIRE_MINS = 10;

    private final MySqlUserService            userService;
    private final EmailVerificationRepository emailVerifRepo;
    private final EmailService                emailService;
    private final RememberMeService           rememberMeService;

    public AuthService() {
        this(new MySqlUserService(),
                new MySqlEmailVerificationRepository(),
                new EmailService(),
                new RememberMeService());
    }

    public AuthService(MySqlUserService userService,
                       EmailVerificationRepository emailVerifRepo,
                       EmailService emailService,
                       RememberMeService rememberMeService) {
        this.userService       = userService;
        this.emailVerifRepo    = emailVerifRepo;
        this.emailService      = emailService;
        this.rememberMeService = rememberMeService;
    }


    /**
     * Đăng ký tài khoản mới.
     * Sau khi tạo xong sẽ gửi OTP đến email; tài khoản chưa active cho đến khi xác nhận.
     *
     * @param username    tên đăng nhập
     * @param displayName tên hiển thị
     * @param email       email nhận OTP
     * @param password    mật khẩu
     * @return User vừa tạo (is_active = false, chờ xác nhận email)
     * @throws IllegalArgumentException nếu dữ liệu không hợp lệ hoặc username / email đã tồn tại
     * @throws DataAccessException      nếu lỗi DB
     * @throws MessagingException       nếu không gửi được email
     */
    public User register(String username, String displayName, String email, String password)
            throws DataAccessException, MessagingException {

        validateUsername(username);
        validatePassword(password);
        validateEmail(email);

        if (userService.getUserByUsername(username) != null) {
            throw new IllegalArgumentException("Tên đăng nhập đã tồn tại.");
        }
        if (userService.getUserByEmail(email) != null) {
            throw new IllegalArgumentException("Email này đã được sử dụng.");
        }

        String passwordHash = CryptUtils.md5(password);
        // Tạo tài khoản với is_active = false, chờ xác nhận email
        userService.createUserWithEmail(username,
                displayName != null && !displayName.isBlank() ? displayName : username,
                email,
                passwordHash,
                Role.PLAYER,
                false /* is_active */);

        User newUser = userService.getAuthUserByUsername(username);
        try {
            sendOtp(newUser);
        } catch (Exception e) {
            try { userService.deleteUser(newUser.getId()); } catch (Exception ignored) {}
            if (e instanceof MessagingException me) throw me;
            if (e instanceof DataAccessException dae) throw dae;
            throw new DataAccessException("Failed to send OTP", e);
        }
        return newUser;
    }


    /**
     * Xác nhận OTP người dùng nhập.
     * Nếu đúng → kích hoạt tài khoản, xoá token.
     *
     * @param userId userId cần xác nhận
     * @param otp    mã 6 số plain-text người dùng nhập
     */
    public void verifyEmail(long userId, String otp) throws DataAccessException {
        if (otp == null || otp.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mã OTP.");
        }

        EmailVerificationToken token = emailVerifRepo.findActiveByUserId(userId);
        if (token == null) {
            throw new IllegalArgumentException("Mã OTP không còn hiệu lực. Vui lòng yêu cầu gửi lại.");
        }
        if (!token.isValid()) {
            throw new IllegalArgumentException("Mã OTP đã hết hạn. Vui lòng yêu cầu gửi lại.");
        }

        if (!CryptUtils.matchesMd5(otp.trim(), token.getOtp())) {
            throw new IllegalArgumentException("Mã OTP không đúng.");
        }

        userService.setActive(userId, true);
        emailVerifRepo.markUsed(token.getId());
        emailVerifRepo.deleteByUserId(userId);
    }

    /**
     * Gửi lại OTP mới đến email của user (dành cho trường hợp hết hạn hoặc không nhận được).
     */
    public void resendOtp(long userId) throws DataAccessException, MessagingException {
        User user = userService.getAuthUserByUsername(
                userService.getUserById(userId).getUsername());
        if (user == null) {
            throw new IllegalArgumentException("Tài khoản không tồn tại.");
        }
        if (user.isActive()) {
            throw new IllegalArgumentException("Tài khoản đã được xác nhận.");
        }
        sendOtp(user);
    }


    /**
     * Đăng nhập. Nếu {@code rememberMe = true} sẽ lưu token "Ghi nhớ đăng nhập".
     *
     * @param username   tên đăng nhập
     * @param password   mật khẩu
     * @param rememberMe tích "Ghi nhớ đăng nhập" hay không
     */
    public User login(String username, String password, boolean rememberMe)
            throws DataAccessException {

        validateUsername(username);
        if (password == null || password.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mật khẩu.");
        }

        User user = userService.getAuthUserByUsername(username);
        if (user == null) {
            throw new IllegalArgumentException("Sai tên đăng nhập hoặc mật khẩu.");
        }
        if (!user.isActive()) {
            boolean hasToken = emailVerifRepo.findActiveByUserId(user.getId()) != null
                    || !user.isActive();
            if (hasToken) {
                throw new IllegalArgumentException("Tài khoản chưa xác nhận email. Vui lòng kiểm tra hộp thư.");
            }
            throw new IllegalArgumentException("Tài khoản đã bị khóa.");
        }
        if (!CryptUtils.matchesMd5(password, user.getPasswordHash())) {
            throw new IllegalArgumentException("Sai tên đăng nhập hoặc mật khẩu.");
        }

        userService.updateLastLogin(user.getId());
        SessionManager.createSession(user);

        if (rememberMe) {
            rememberMeService.save(user);
        } else {
            rememberMeService.clear();
        }

        return user;
    }

    public User login(String username, String password) throws DataAccessException {
        return login(username, password, false);
    }


    public void logout() {
        rememberMeService.clear();
        SessionManager.clearSession();
    }


    public void changePassword(long userId, String currentPassword, String newPassword)
            throws DataAccessException {
        if (currentPassword == null || currentPassword.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mật khẩu hiện tại.");
        }
        validatePassword(newPassword);

        String storedHash = userService.getPasswordHashById(userId);
        if (storedHash == null || !CryptUtils.matchesMd5(currentPassword, storedHash)) {
            throw new IllegalArgumentException("Mật khẩu hiện tại không đúng.");
        }

        userService.updatePasswordHash(userId, CryptUtils.md5(newPassword));
    }


    /**
     * Thử đăng nhập tự động bằng token "Ghi nhớ đăng nhập" khi mở app.
     * @return User nếu thành công, null nếu không có token hoặc token hết hạn.
     */
    public User tryAutoLogin() {
        return rememberMeService.tryAutoLogin();
    }

    private void sendOtp(User user) throws DataAccessException, MessagingException {
        String plainOtp  = generateOtp();
        String hashedOtp = CryptUtils.md5(plainOtp);

        EmailVerificationToken token = new EmailVerificationToken();
        token.setUserId   (user.getId());
        token.setEmail    (user.getEmail());
        token.setOtp      (hashedOtp);
        token.setExpiresAt(LocalDateTime.now().plusMinutes(OTP_EXPIRE_MINS));
        emailVerifRepo.save(token);

        emailService.sendOtpEmail(user.getEmail(), plainOtp);
    }

    private String generateOtp() {
        SecureRandom rng = new SecureRandom();
        int code = 100_000 + rng.nextInt(900_000);
        return String.valueOf(code);
    }

    private void validateUsername(String username) {
        if (username == null || username.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập tên đăng nhập.");
        }
        if (username.contains(" ")) {
            throw new IllegalArgumentException("Tên đăng nhập không được chứa khoảng trắng.");
        }
        if (username.trim().length() < 3) {
            throw new IllegalArgumentException("Tên đăng nhập cần ít nhất 3 ký tự.");
        }
    }

    private void validatePassword(String password) {
        if (password == null || password.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mật khẩu.");
        }
        if (password.length() < 6) {
            throw new IllegalArgumentException("Mật khẩu cần ít nhất 6 ký tự.");
        }
    }

    private void validateEmail(String email) {
        if (email == null || email.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập email.");
        }
        if (!email.matches("^[\\w._%+\\-]+@[\\w.\\-]+\\.[a-zA-Z]{2,}$")) {
            throw new IllegalArgumentException("Địa chỉ email không hợp lệ.");
        }
    }
}

package minesweeper.service;

import minesweeper.model.EmailVerificationToken;
import minesweeper.model.enums.Role;
import minesweeper.model.User;
import minesweeper.repository.EmailVerificationRepository;
import minesweeper.repository.MySqlEmailVerificationRepository;
import minesweeper.repository.exception.DataAccessException;
import utils.CryptUtils;

import jakarta.mail.MessagingException;
import java.security.SecureRandom;
import java.time.LocalDateTime;

public class AuthService {

    private static final int OTP_LENGTH      = 6;
    private static final int OTP_EXPIRE_MINS = 10;

    private final MySqlUserService            userService;
    private final EmailVerificationRepository emailVerifRepo;
    private final EmailService                emailService;
    private final RememberMeService           rememberMeService;

    public AuthService() {
        this(new MySqlUserService(),
                new MySqlEmailVerificationRepository(),
                new EmailService(),
                new RememberMeService());
    }

    public AuthService(MySqlUserService userService,
                       EmailVerificationRepository emailVerifRepo,
                       EmailService emailService,
                       RememberMeService rememberMeService) {
        this.userService       = userService;
        this.emailVerifRepo    = emailVerifRepo;
        this.emailService      = emailService;
        this.rememberMeService = rememberMeService;
    }


    /**
     * Đăng ký tài khoản mới.
     * Sau khi tạo xong sẽ gửi OTP đến email; tài khoản chưa active cho đến khi xác nhận.
     *
     * @param username    tên đăng nhập
     * @param displayName tên hiển thị
     * @param email       email nhận OTP
     * @param password    mật khẩu
     * @return User vừa tạo (is_active = false, chờ xác nhận email)
     * @throws IllegalArgumentException nếu dữ liệu không hợp lệ hoặc username / email đã tồn tại
     * @throws DataAccessException      nếu lỗi DB
     * @throws MessagingException       nếu không gửi được email
     */
    public User register(String username, String displayName, String email, String password)
            throws DataAccessException, MessagingException {

        validateUsername(username);
        validatePassword(password);
        validateEmail(email);

        if (userService.getUserByUsername(username) != null) {
            throw new IllegalArgumentException("Tên đăng nhập đã tồn tại.");
        }
        if (userService.getUserByEmail(email) != null) {
            throw new IllegalArgumentException("Email này đã được sử dụng.");
        }

        String passwordHash = CryptUtils.md5(password);
        userService.createUserWithEmail(username,
                displayName != null && !displayName.isBlank() ? displayName : username,
                email,
                passwordHash,
                Role.PLAYER,
                false);

        User newUser = userService.getAuthUserByUsername(username);
        try {
            sendOtp(newUser);
        } catch (Exception e) {
            try { userService.deleteUser(newUser.getId()); } catch (Exception ignored) {}
            if (e instanceof MessagingException me) throw me;
            if (e instanceof DataAccessException dae) throw dae;
            throw new DataAccessException("Failed to send OTP", e);
        }
        return newUser;
    }


    /**
     * Xác nhận OTP người dùng nhập.
     * Nếu đúng → kích hoạt tài khoản, xoá token.
     *
     * @param userId userId cần xác nhận
     * @param otp    mã 6 số plain-text người dùng nhập
     */
    public void verifyEmail(long userId, String otp) throws DataAccessException {
        if (otp == null || otp.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mã OTP.");
        }

        EmailVerificationToken token = emailVerifRepo.findActiveByUserId(userId);
        if (token == null) {
            throw new IllegalArgumentException("Mã OTP không còn hiệu lực. Vui lòng yêu cầu gửi lại.");
        }
        if (!token.isValid()) {
            throw new IllegalArgumentException("Mã OTP đã hết hạn. Vui lòng yêu cầu gửi lại.");
        }

        if (!CryptUtils.matchesMd5(otp.trim(), token.getOtp())) {
            throw new IllegalArgumentException("Mã OTP không đúng.");
        }

        userService.setActive(userId, true);
        emailVerifRepo.markUsed(token.getId());
        emailVerifRepo.deleteByUserId(userId);
    }

    /**
     * Gửi lại OTP mới đến email của user (dành cho trường hợp hết hạn hoặc không nhận được).
     */
    public void resendOtp(long userId) throws DataAccessException, MessagingException {
        User user = userService.getAuthUserByUsername(
                userService.getUserById(userId).getUsername());
        if (user == null) {
            throw new IllegalArgumentException("Tài khoản không tồn tại.");
        }
        if (user.isActive()) {
            throw new IllegalArgumentException("Tài khoản đã được xác nhận.");
        }
        sendOtp(user);
    }


    /**
     * Đăng nhập. Nếu {@code rememberMe = true} sẽ lưu token "Ghi nhớ đăng nhập".
     *
     * @param username   tên đăng nhập
     * @param password   mật khẩu
     * @param rememberMe tích "Ghi nhớ đăng nhập" hay không
     */
    public User login(String username, String password, boolean rememberMe)
            throws DataAccessException {

        validateUsername(username);
        if (password == null || password.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mật khẩu.");
        }

        User user = userService.getAuthUserByUsername(username);
        if (user == null) {
            throw new IllegalArgumentException("Sai tên đăng nhập hoặc mật khẩu.");
        }
        if (!user.isActive()) {
            boolean hasToken = emailVerifRepo.findActiveByUserId(user.getId()) != null
                    || !user.isActive();
            if (hasToken) {
                throw new IllegalArgumentException("Tài khoản chưa xác nhận email. Vui lòng kiểm tra hộp thư.");
            }
            throw new IllegalArgumentException("Tài khoản đã bị khóa.");
        }
        if (!CryptUtils.matchesMd5(password, user.getPasswordHash())) {
            throw new IllegalArgumentException("Sai tên đăng nhập hoặc mật khẩu.");
        }

        userService.updateLastLogin(user.getId());
        SessionManager.createSession(user);

        if (rememberMe) {
            rememberMeService.save(user);
        } else {
            rememberMeService.clear();
        }

        return user;
    }

    public User login(String username, String password) throws DataAccessException {
        return login(username, password, false);
    }


    public void logout() {
        rememberMeService.clear();
        SessionManager.clearSession();
    }


    public void changePassword(long userId, String currentPassword, String newPassword)
            throws DataAccessException {
        if (currentPassword == null || currentPassword.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mật khẩu hiện tại.");
        }
        validatePassword(newPassword);

        String storedHash = userService.getPasswordHashById(userId);
        if (storedHash == null || !CryptUtils.matchesMd5(currentPassword, storedHash)) {
            throw new IllegalArgumentException("Mật khẩu hiện tại không đúng.");
        }

        userService.updatePasswordHash(userId, CryptUtils.md5(newPassword));
    }


    /**
     * Thử đăng nhập tự động bằng token "Ghi nhớ đăng nhập" khi mở app.
     * @return User nếu thành công, null nếu không có token hoặc token hết hạn.
     */
    public User tryAutoLogin() {
        return rememberMeService.tryAutoLogin();
    }

    private void sendOtp(User user) throws DataAccessException, MessagingException {
        String plainOtp  = generateOtp();
        String hashedOtp = CryptUtils.md5(plainOtp);

        EmailVerificationToken token = new EmailVerificationToken();
        token.setUserId   (user.getId());
        token.setEmail    (user.getEmail());
        token.setOtp      (hashedOtp);
        token.setExpiresAt(LocalDateTime.now().plusMinutes(OTP_EXPIRE_MINS));
        emailVerifRepo.save(token);

        emailService.sendOtpEmail(user.getEmail(), plainOtp);
    }

    private String generateOtp() {
        SecureRandom rng = new SecureRandom();
        int code = 100_000 + rng.nextInt(900_000);
        return String.valueOf(code);
    }

    private void validateUsername(String username) {
        if (username == null || username.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập tên đăng nhập.");
        }
        if (username.contains(" ")) {
            throw new IllegalArgumentException("Tên đăng nhập không được chứa khoảng trắng.");
        }
        if (username.trim().length() < 3) {
            throw new IllegalArgumentException("Tên đăng nhập cần ít nhất 3 ký tự.");
        }
    }

    private void validatePassword(String password) {
        if (password == null || password.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập mật khẩu.");
        }
        if (password.length() < 6) {
            throw new IllegalArgumentException("Mật khẩu cần ít nhất 6 ký tự.");
        }
    }

    private void validateEmail(String email) {
        if (email == null || email.isBlank()) {
            throw new IllegalArgumentException("Vui lòng nhập email.");
        }
        if (!email.matches("^[\\w._%+\\-]+@[\\w.\\-]+\\.[a-zA-Z]{2,}$")) {
            throw new IllegalArgumentException("Địa chỉ email không hợp lệ.");
        }
    }
}

package minesweeper.controller;

import javafx.application.Platform;
import javafx.fxml.FXML;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;
import minesweeper.repository.exception.DataAccessException;
import minesweeper.service.AuthService;
import minesweeper.service.ForgotPasswordService;
import minesweeper.model.User;

import jakarta.mail.MessagingException;
import java.util.Optional;

/**
 * LoginController mở rộng:
 *  - Form đăng ký thêm field Email
 *  - Checkbox "Ghi nhớ đăng nhập" trên form login
 *  - Sau đăng ký hiện dialog nhập OTP
 *  - Nút "Gửi lại OTP" trên dialog OTP
 */
public class LoginController {

    // ── FXML bindings (giữ nguyên các field cũ) ───────────────────────────────

    @FXML private Label  formTitle;
    @FXML private Label  formSubtitle;
    @FXML private VBox   loginForm;
    @FXML private VBox   registerForm;
    @FXML private Button loginTabButton;
    @FXML private Button registerTabButton;

    // Login form
    @FXML private TextField     loginUsernameField;
    @FXML private PasswordField loginPasswordField;
    @FXML private CheckBox      rememberMeCheckBox;   // MỚI

    // Register form
    @FXML private TextField     registerUsernameField;
    @FXML private TextField     registerDisplayNameField;
    @FXML private TextField     registerEmailField;       // MỚI
    @FXML private PasswordField registerPasswordField;
    @FXML private PasswordField registerConfirmPasswordField;

    // ── State ─────────────────────────────────────────────────────────────────

    private final AuthService authService = new AuthService();
    private Runnable onLoginSuccess;

    /** userId chờ xác nhận OTP sau đăng ký. */
    private long pendingVerifyUserId = -1;

    // ── Callback ──────────────────────────────────────────────────────────────

    public void setOnLoginSuccess(Runnable callback) {
        this.onLoginSuccess = callback;
    }

    // ── Tab switching (giữ nguyên) ────────────────────────────────────────────

    public void showLoginForm() {
        formTitle.setText("ĐĂNG NHẬP");
        formSubtitle.setText("Truy cập hồ sơ chiến thuật của bạn");
        loginForm.setVisible(true);
        loginForm.setManaged(true);
        registerForm.setVisible(false);
        registerForm.setManaged(false);
        setActiveTab(loginTabButton, registerTabButton);
        reCenterStage();
    }

    public void showRegisterForm() {
        formTitle.setText("ĐĂNG KÝ");
        formSubtitle.setText("Khởi tạo tài khoản chiến binh mới");
        loginForm.setVisible(false);
        loginForm.setManaged(false);
        registerForm.setVisible(true);
        registerForm.setManaged(true);
        setActiveTab(registerTabButton, loginTabButton);
        reCenterStage();
    }

    public void openAsLogin()    { showLoginForm(); }
    public void openAsRegister() { showRegisterForm(); }

    // ── Handlers ──────────────────────────────────────────────────────────────

    @FXML
    private void closePopup() {
        getStage().close();
    }

    @FXML
    private void handleLogin() {
        String username   = text(loginUsernameField);
        String password   = text(loginPasswordField);
        boolean remember  = rememberMeCheckBox != null && rememberMeCheckBox.isSelected();

        try {
            authService.login(username, password, remember);
            clearLoginFields();
            if (onLoginSuccess != null) onLoginSuccess.run();
            HeaderController.refreshAllInstances();
            DashBoardController.refreshAllInstances();
            closePopup();
        } catch (IllegalArgumentException e) {
            showError(e.getMessage());
        } catch (DataAccessException e) {
            showError("Không thể đăng nhập. Vui lòng thử lại.");
        }
    }

    @FXML
    private void handleRegister() {
        String username       = text(registerUsernameField);
        String displayName    = text(registerDisplayNameField);
        String email          = text(registerEmailField);
        String password       = text(registerPasswordField);
        String confirmPassword= text(registerConfirmPasswordField);

        if (password == null || !password.equals(confirmPassword)) {
            showError("Mật khẩu xác nhận không khớp.");
            return;
        }
        if (displayName == null || displayName.isBlank()) {
            displayName = username;
        }

        try {
            User newUser = authService.register(username, displayName, email, password);
            pendingVerifyUserId = newUser.getId();
            clearRegisterFields();
            showOtpDialog(email);
        } catch (IllegalArgumentException e) {
            showError(e.getMessage());
        } catch (DataAccessException e) {
            showError("Không thể đăng ký. Vui lòng thử lại.");
        } catch (MessagingException e) {
            showError("Đăng ký thành công nhưng không gửi được email xác nhận.\n" +
                    "Vui lòng liên hệ admin.");
        }
    }

    // ── OTP Dialog ────────────────────────────────────────────────────────────

    /**
     * Hiển thị dialog nhập OTP sau khi đăng ký.
     * Người dùng có thể nhập mã hoặc yêu cầu gửi lại.
     */
    private void showOtpDialog(String email) {
        VBox content = new VBox(16);
        content.setStyle("-fx-padding: 20px; -fx-spacing: 12px;");

        Label title = new Label("✓ KIỂM CHỨNG EMAIL");
        title.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 16px; -fx-font-weight: 900; -fx-letter-spacing: 2px;");

        Label header = new Label("Mã OTP đã được gửi!");
        header.setStyle("-fx-text-fill: #21d9ff; -fx-font-size: 13px; -fx-font-weight: 700;");

        Label emailLabel = new Label("Đến: " + email);
        emailLabel.setStyle("-fx-text-fill: #8fcddd; -fx-font-size: 12px;");

        VBox timerBox = new VBox(4);
        timerBox.setStyle("-fx-background-color: rgba(49, 255, 155, 0.1); -fx-border-color: rgba(49, 255, 155, 0.3); "
                + "-fx-border-radius: 8; -fx-padding: 10px; -fx-border-width: 1;");
        Label timerLabel = new Label("⏱ Mã có hiệu lực trong 10 phút");
        timerLabel.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 12px; -fx-font-weight: 700;");
        timerBox.getChildren().add(timerLabel);

        Label otpLabel = new Label("Nhập mã OTP (6 chữ số):");
        otpLabel.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 11px; -fx-font-weight: 900; -fx-letter-spacing: 1px;");

        TextField otpField = new TextField();
        otpField.setPromptText("000000");
        otpField.setStyle("-fx-background-color: rgba(3, 16, 25, 0.95); -fx-background-radius: 10; "
                + "-fx-border-radius: 10; -fx-border-width: 1.5; -fx-border-color: rgba(33, 217, 255, 0.35); "
                + "-fx-text-fill: #d7fbff; -fx-prompt-text-fill: rgba(112, 199, 220, 0.5); "
                + "-fx-font-size: 20; -fx-font-weight: 900; -fx-font-family: 'Courier New'; -fx-padding: 14px; "
                + "-fx-text-alignment: center; -fx-letter-spacing: 6;");
        otpField.setMaxWidth(200);

        Button resendBtn = new Button("↻ Gửi lại OTP");
        resendBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #23d4ff; -fx-font-size: 11px; "
                + "-fx-font-weight: 700; -fx-cursor: hand; -fx-underline: true; -fx-padding: 4;");
        resendBtn.setOnAction(e -> handleResendOtp(email));
        resendBtn.setOnMouseEntered(e -> resendBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #31ff9b; "
                + "-fx-font-size: 11px; -fx-font-weight: 700; -fx-cursor: hand; -fx-underline: true; -fx-padding: 4;"));
        resendBtn.setOnMouseExited(e -> resendBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #23d4ff; "
                + "-fx-font-size: 11px; -fx-font-weight: 700; -fx-cursor: hand; -fx-underline: true; -fx-padding: 4;"));

        HBox resendBox = new HBox();
        resendBox.setStyle("-fx-alignment: center;");
        resendBox.getChildren().add(resendBtn);

        content.getChildren().addAll(title, header, emailLabel, timerBox, otpLabel, otpField, resendBox);

        Dialog<String> dialog = new Dialog<>();
        dialog.setTitle("Xác nhận Email");
        dialog.setHeaderText(null);
        dialog.getDialogPane().setStyle("-fx-background-color: linear-gradient(to bottom right, rgba(5, 20, 28, 0.98), rgba(5, 10, 18, 0.98)); "
                + "-fx-border-color: rgba(48, 255, 170, 0.35); -fx-border-radius: 12; -fx-background-radius: 12;");
        dialog.getDialogPane().setContent(content);
        dialog.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);

        Button okButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.OK);
        okButton.setText("✓ XÁC NHẬN");
        okButton.setStyle("-fx-background-color: linear-gradient(to right, #31ff9b, #35d5ff); -fx-background-radius: 8; "
                + "-fx-border-radius: 8; -fx-text-fill: #021016; -fx-font-size: 12px; -fx-font-weight: 800; "
                + "-fx-padding: 10px 20px; -fx-cursor: hand;");

        Button cancelButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.CANCEL);
        cancelButton.setText("✕ HUỶ");
        cancelButton.setStyle("-fx-background-color: rgba(255, 76, 122, 0.12); -fx-border-color: rgba(255, 76, 122, 0.55); "
                + "-fx-border-radius: 8; -fx-background-radius: 8; -fx-text-fill: #ff4c7a; -fx-font-size: 12px; "
                + "-fx-font-weight: 800; -fx-padding: 10px 20px; -fx-cursor: hand;");

        okButton.addEventFilter(javafx.event.ActionEvent.ACTION, event -> {
            String otp = otpField.getText().trim();
            if (otp.isEmpty() || otp.length() != 6 || !otp.matches("\\d{6}")) {
                showError("Mã OTP phải có đúng 6 chữ số.");
                event.consume();
            }
        });

        dialog.setResultConverter(btn -> {
            if (btn == ButtonType.OK) return otpField.getText();
            return null;
        });

        Optional<String> result = dialog.showAndWait();
        result.ifPresentOrElse(
                otp -> handleVerifyOtp(otp.trim()),
                () -> showInfo("Bạn có thể xác nhận email sau khi đăng nhập.")
        );
    }

    private void handleVerifyOtp(String otp) {
        if (pendingVerifyUserId < 0) return;
        long userIdBackup = pendingVerifyUserId;
        try {
            authService.verifyEmail(pendingVerifyUserId, otp);
            pendingVerifyUserId = -1;
            showInfo("Xác nhận email thành công! Vui lòng đăng nhập.");
            showLoginForm();
        } catch (IllegalArgumentException e) {
            showError(e.getMessage());
            // Mở lại dialog nếu OTP sai
            User u = null;
            try { u = new minesweeper.service.MySqlUserService().getUserById(userIdBackup); } catch (Exception ignored) {}
            if (u != null) showOtpDialog(u.getEmail());
        } catch (DataAccessException e) {
            showError("Không thể xác nhận. Vui lòng thử lại.");
        }
    }

    private void handleResendOtp(String email) {
        if (pendingVerifyUserId < 0) return;
        try {
            authService.resendOtp(pendingVerifyUserId);
            showInfo("Đã gửi lại OTP đến " + email);
        } catch (Exception e) {
            showError("Không thể gửi lại OTP: " + e.getMessage());
        }
    }

    // ── Forgot Password ────────────────────────────────────────────────────────

    @FXML
    private void handleForgotPassword() {
        VBox content = new VBox(16);
        content.setStyle("-fx-padding: 20px; -fx-spacing: 12px;");

        Label title = new Label("? QUÊN MẬT KHẨU");
        title.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 16px; -fx-font-weight: 900; -fx-letter-spacing: 2px;");

        Label header = new Label("Nhập email để khôi phục mật khẩu");
        header.setStyle("-fx-text-fill: #21d9ff; -fx-font-size: 13px; -fx-font-weight: 700;");

        Label infoLabel = new Label("Chúng tôi sẽ gửi link đặt lại mật khẩu đến email của bạn. "
                + "Link sẽ hết hạn trong 30 phút.");
        infoLabel.setWrapText(true);
        infoLabel.setStyle("-fx-text-fill: #8fcddd; -fx-font-size: 12px; -fx-wrap-text: true;");

        Label emailPromptLabel = new Label("Địa chỉ Email:");
        emailPromptLabel.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 11px; -fx-font-weight: 900; -fx-letter-spacing: 1px;");

        TextField emailField = new TextField();
        emailField.setPromptText("your@email.com");
        emailField.setStyle("-fx-background-color: rgba(3, 16, 25, 0.95); -fx-background-radius: 10; "
                + "-fx-border-radius: 10; -fx-border-width: 1.5; -fx-border-color: rgba(33, 217, 255, 0.35); "
                + "-fx-text-fill: #d7fbff; -fx-prompt-text-fill: rgba(112, 199, 220, 0.5); "
                + "-fx-font-size: 13px; -fx-padding: 12px 14px;");

        content.getChildren().addAll(title, header, infoLabel, emailPromptLabel, emailField);

        Dialog<String> dialog = new Dialog<>();
        dialog.setTitle("Quên mật khẩu");
        dialog.setHeaderText(null);
        dialog.getDialogPane().setStyle("-fx-background-color: linear-gradient(to bottom right, rgba(5, 20, 28, 0.98), rgba(5, 10, 18, 0.98)); "
                + "-fx-border-color: rgba(48, 255, 170, 0.35); -fx-border-radius: 12; -fx-background-radius: 12;");
        dialog.getDialogPane().setContent(content);
        dialog.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);

        Button okButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.OK);
        okButton.setText(" GỬI LINK");
        okButton.setStyle("-fx-background-color: linear-gradient(to right, #31ff9b, #35d5ff); -fx-background-radius: 8; "
                + "-fx-border-radius: 8; -fx-text-fill: #021016; -fx-font-size: 12px; -fx-font-weight: 800; "
                + "-fx-padding: 10px 20px; -fx-cursor: hand;");

        Button cancelButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.CANCEL);
        cancelButton.setText("✕ HUỶ");
        cancelButton.setStyle("-fx-background-color: rgba(255, 76, 122, 0.12); -fx-border-color: rgba(255, 76, 122, 0.55); "
                + "-fx-border-radius: 8; -fx-background-radius: 8; -fx-text-fill: #ff4c7a; -fx-font-size: 12px; "
                + "-fx-font-weight: 800; -fx-padding: 10px 20px; -fx-cursor: hand;");

        okButton.addEventFilter(javafx.event.ActionEvent.ACTION, event -> {
            String email = emailField.getText().trim();
            if (email.isEmpty()) {
                showError("Vui lòng nhập email.");
                event.consume();
            } else if (!email.matches("^[\\w._%+\\-]+@[\\w.\\-]+\\.[a-zA-Z]{2,}$")) {
                showError("Email không hợp lệ.");
                event.consume();
            }
        });

        dialog.setResultConverter(btn -> {
            if (btn == ButtonType.OK) return emailField.getText();
            return null;
        });

        Optional<String> result = dialog.showAndWait();
        result.ifPresent(email -> {
            try {
                ForgotPasswordService forgotService = new ForgotPasswordService();
                forgotService.sendPasswordResetLink(email.trim());
                showInfo("✓ Link đặt lại mật khẩu đã được gửi đến:\n\n" + email.trim() +
                        "\n\nVui lòng kiểm tra hộp thư (kể cả thư rác). Link có hiệu lực trong 30 phút.");
            } catch (IllegalArgumentException e) {
                showError(e.getMessage());
            } catch (Exception e) {
                showError("Không thể gửi link reset. Vui lòng thử lại sau.");
            }
        });
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private void clearLoginFields() {
        if (loginUsernameField  != null) loginUsernameField.clear();
        if (loginPasswordField  != null) loginPasswordField.clear();
        if (rememberMeCheckBox  != null) rememberMeCheckBox.setSelected(false);
    }

    private void clearRegisterFields() {
        if (registerUsernameField     != null) registerUsernameField.clear();
        if (registerDisplayNameField  != null) registerDisplayNameField.clear();
        if (registerEmailField        != null) registerEmailField.clear();
        if (registerPasswordField     != null) registerPasswordField.clear();
        if (registerConfirmPasswordField != null) registerConfirmPasswordField.clear();
    }

    private void setActiveTab(Button active, Button inactive) {
        active.getStyleClass().removeAll("switch-button", "switch-button-active");
        inactive.getStyleClass().removeAll("switch-button", "switch-button-active");
        active.getStyleClass().add("switch-button-active");
        inactive.getStyleClass().add("switch-button");
    }

    private void showError(String message) {
        Alert alert = new Alert(Alert.AlertType.ERROR);
        alert.setHeaderText("Thông báo");
        alert.setContentText(message);
        alert.showAndWait();
    }

    private void showInfo(String message) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION);
        alert.setHeaderText("Thông báo");
        alert.setContentText(message);
        alert.showAndWait();
    }

    private String text(TextField field) {
        return field != null ? field.getText() : null;
    }

    private Stage getStage() {
        return (Stage) formTitle.getScene().getWindow();
    }

    private void reCenterStage() {
        if (formTitle != null && formTitle.getScene() != null) {
            Platform.runLater(() -> {
                Stage stage = getStage();
                stage.sizeToScene();
                stage.centerOnScreen();
            });
        }
    }
}

package minesweeper.controller;

import javafx.application.Platform;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;
import javafx.stage.Modality;
import minesweeper.repository.exception.DataAccessException;
import minesweeper.service.AuthService;
import minesweeper.service.ForgotPasswordService;
import minesweeper.model.User;

import jakarta.mail.MessagingException;
import java.io.IOException;
import java.util.Optional;

/**
 * LoginController mở rộng:
 *  - Form đăng ký thêm field Email
 *  - Checkbox "Ghi nhớ đăng nhập" trên form login
 *  - Sau đăng ký hiện dialog nhập OTP
 *  - Nút "Gửi lại OTP" trên dialog OTP
 */
public class LoginController {

    // ── FXML bindings (giữ nguyên các field cũ) ───────────────────────────────

    @FXML private Label  formTitle;
    @FXML private Label  formSubtitle;
    @FXML private VBox   loginForm;
    @FXML private VBox   registerForm;
    @FXML private Button loginTabButton;
    @FXML private Button registerTabButton;

    // Login form
    @FXML private TextField     loginUsernameField;
    @FXML private PasswordField loginPasswordField;
    @FXML private CheckBox      rememberMeCheckBox;   // MỚI

    // Register form
    @FXML private TextField     registerUsernameField;
    @FXML private TextField     registerDisplayNameField;
    @FXML private TextField     registerEmailField;       // MỚI
    @FXML private PasswordField registerPasswordField;
    @FXML private PasswordField registerConfirmPasswordField;

    // ── State ─────────────────────────────────────────────────────────────────

    private final AuthService authService = new AuthService();
    private Runnable onLoginSuccess;

    /** userId chờ xác nhận OTP sau đăng ký. */
    private long pendingVerifyUserId = -1;

    // ── Callback ──────────────────────────────────────────────────────────────

    public void setOnLoginSuccess(Runnable callback) {
        this.onLoginSuccess = callback;
    }

    // ── Tab switching (giữ nguyên) ────────────────────────────────────────────

    public void showLoginForm() {
        formTitle.setText("ĐĂNG NHẬP");
        formSubtitle.setText("Truy cập hồ sơ chiến thuật của bạn");
        loginForm.setVisible(true);
        loginForm.setManaged(true);
        registerForm.setVisible(false);
        registerForm.setManaged(false);
        setActiveTab(loginTabButton, registerTabButton);
        reCenterStage();
    }

    public void showRegisterForm() {
        formTitle.setText("ĐĂNG KÝ");
        formSubtitle.setText("Khởi tạo tài khoản chiến binh mới");
        loginForm.setVisible(false);
        loginForm.setManaged(false);
        registerForm.setVisible(true);
        registerForm.setManaged(true);
        setActiveTab(registerTabButton, loginTabButton);
        reCenterStage();
    }

    public void openAsLogin()    { showLoginForm(); }
    public void openAsRegister() { showRegisterForm(); }

    // ── Handlers ──────────────────────────────────────────────────────────────

    @FXML
    private void closePopup() {
        getStage().close();
    }

    @FXML
    private void handleLogin() {
        String username   = text(loginUsernameField);
        String password   = text(loginPasswordField);
        boolean remember  = rememberMeCheckBox != null && rememberMeCheckBox.isSelected();

        try {
            authService.login(username, password, remember);
            clearLoginFields();
            if (onLoginSuccess != null) onLoginSuccess.run();
            HeaderController.refreshAllInstances();
            DashBoardController.refreshAllInstances();
            closePopup();
        } catch (IllegalArgumentException e) {
            showError(e.getMessage());
        } catch (DataAccessException e) {
            showError("Không thể đăng nhập. Vui lòng thử lại.");
        }
    }

    @FXML
    private void handleRegister() {
        String username       = text(registerUsernameField);
        String displayName    = text(registerDisplayNameField);
        String email          = text(registerEmailField);
        String password       = text(registerPasswordField);
        String confirmPassword= text(registerConfirmPasswordField);

        if (password == null || !password.equals(confirmPassword)) {
            showError("Mật khẩu xác nhận không khớp.");
            return;
        }
        if (displayName == null || displayName.isBlank()) {
            displayName = username;
        }

        try {
            User newUser = authService.register(username, displayName, email, password);
            pendingVerifyUserId = newUser.getId();
            clearRegisterFields();
            showOtpDialog(email);
        } catch (IllegalArgumentException e) {
            showError(e.getMessage());
        } catch (DataAccessException e) {
            showError("Không thể đăng ký. Vui lòng thử lại.");
        } catch (MessagingException e) {
            showError("Đăng ký thành công nhưng không gửi được email xác nhận.\n" +
                    "Vui lòng liên hệ admin.");
        }
    }

    // ── OTP Dialog ────────────────────────────────────────────────────────────

    /**
     * Hiển thị dialog nhập OTP sau khi đăng ký.
     * Người dùng có thể nhập mã hoặc yêu cầu gửi lại.
     */
    private void showOtpDialog(String email) {
        VBox content = new VBox(16);
        content.setStyle("-fx-padding: 20px; -fx-spacing: 12px;");

        Label title = new Label("✓ KIỂM CHỨNG EMAIL");
        title.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 16px; -fx-font-weight: 900; -fx-letter-spacing: 2px;");

        Label header = new Label("Mã OTP đã được gửi!");
        header.setStyle("-fx-text-fill: #21d9ff; -fx-font-size: 13px; -fx-font-weight: 700;");

        Label emailLabel = new Label("Đến: " + email);
        emailLabel.setStyle("-fx-text-fill: #8fcddd; -fx-font-size: 12px;");

        VBox timerBox = new VBox(4);
        timerBox.setStyle("-fx-background-color: rgba(49, 255, 155, 0.1); -fx-border-color: rgba(49, 255, 155, 0.3); "
                + "-fx-border-radius: 8; -fx-padding: 10px; -fx-border-width: 1;");
        Label timerLabel = new Label("⏱ Mã có hiệu lực trong 10 phút");
        timerLabel.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 12px; -fx-font-weight: 700;");
        timerBox.getChildren().add(timerLabel);

        Label otpLabel = new Label("Nhập mã OTP (6 chữ số):");
        otpLabel.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 11px; -fx-font-weight: 900; -fx-letter-spacing: 1px;");

        TextField otpField = new TextField();
        otpField.setPromptText("000000");
        otpField.setStyle("-fx-background-color: rgba(3, 16, 25, 0.95); -fx-background-radius: 10; "
                + "-fx-border-radius: 10; -fx-border-width: 1.5; -fx-border-color: rgba(33, 217, 255, 0.35); "
                + "-fx-text-fill: #d7fbff; -fx-prompt-text-fill: rgba(112, 199, 220, 0.5); "
                + "-fx-font-size: 20; -fx-font-weight: 900; -fx-font-family: 'Courier New'; -fx-padding: 14px; "
                + "-fx-text-alignment: center; -fx-letter-spacing: 6;");
        otpField.setMaxWidth(200);

        Button resendBtn = new Button("↻ Gửi lại OTP");
        resendBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #23d4ff; -fx-font-size: 11px; "
                + "-fx-font-weight: 700; -fx-cursor: hand; -fx-underline: true; -fx-padding: 4;");
        resendBtn.setOnAction(e -> handleResendOtp(email));
        resendBtn.setOnMouseEntered(e -> resendBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #31ff9b; "
                + "-fx-font-size: 11px; -fx-font-weight: 700; -fx-cursor: hand; -fx-underline: true; -fx-padding: 4;"));
        resendBtn.setOnMouseExited(e -> resendBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #23d4ff; "
                + "-fx-font-size: 11px; -fx-font-weight: 700; -fx-cursor: hand; -fx-underline: true; -fx-padding: 4;"));

        HBox resendBox = new HBox();
        resendBox.setStyle("-fx-alignment: center;");
        resendBox.getChildren().add(resendBtn);

        content.getChildren().addAll(title, header, emailLabel, timerBox, otpLabel, otpField, resendBox);

        Dialog<String> dialog = new Dialog<>();
        dialog.setTitle("Xác nhận Email");
        dialog.setHeaderText(null);
        dialog.getDialogPane().setStyle("-fx-background-color: linear-gradient(to bottom right, rgba(5, 20, 28, 0.98), rgba(5, 10, 18, 0.98)); "
                + "-fx-border-color: rgba(48, 255, 170, 0.35); -fx-border-radius: 12; -fx-background-radius: 12;");
        dialog.getDialogPane().setContent(content);
        dialog.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);

        Button okButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.OK);
        okButton.setText("✓ XÁC NHẬN");
        okButton.setStyle("-fx-background-color: linear-gradient(to right, #31ff9b, #35d5ff); -fx-background-radius: 8; "
                + "-fx-border-radius: 8; -fx-text-fill: #021016; -fx-font-size: 12px; -fx-font-weight: 800; "
                + "-fx-padding: 10px 20px; -fx-cursor: hand;");

        Button cancelButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.CANCEL);
        cancelButton.setText("✕ HUỶ");
        cancelButton.setStyle("-fx-background-color: rgba(255, 76, 122, 0.12); -fx-border-color: rgba(255, 76, 122, 0.55); "
                + "-fx-border-radius: 8; -fx-background-radius: 8; -fx-text-fill: #ff4c7a; -fx-font-size: 12px; "
                + "-fx-font-weight: 800; -fx-padding: 10px 20px; -fx-cursor: hand;");

        okButton.addEventFilter(javafx.event.ActionEvent.ACTION, event -> {
            String otp = otpField.getText().trim();
            if (otp.isEmpty() || otp.length() != 6 || !otp.matches("\\d{6}")) {
                showError("Mã OTP phải có đúng 6 chữ số.");
                event.consume();
            }
        });

        dialog.setResultConverter(btn -> {
            if (btn == ButtonType.OK) return otpField.getText();
            return null;
        });

        Optional<String> result = dialog.showAndWait();
        result.ifPresentOrElse(
                otp -> handleVerifyOtp(otp.trim()),
                () -> showInfo("Bạn có thể xác nhận email sau khi đăng nhập.")
        );
    }

    private void handleVerifyOtp(String otp) {
        if (pendingVerifyUserId < 0) return;
        long userIdBackup = pendingVerifyUserId;
        try {
            authService.verifyEmail(pendingVerifyUserId, otp);
            pendingVerifyUserId = -1;
            showInfo("Xác nhận email thành công! Vui lòng đăng nhập.");
            showLoginForm();
        } catch (IllegalArgumentException e) {
            showError(e.getMessage());
            // Mở lại dialog nếu OTP sai
            User u = null;
            try { u = new minesweeper.service.MySqlUserService().getUserById(userIdBackup); } catch (Exception ignored) {}
            if (u != null) showOtpDialog(u.getEmail());
        } catch (DataAccessException e) {
            showError("Không thể xác nhận. Vui lòng thử lại.");
        }
    }

    private void handleResendOtp(String email) {
        if (pendingVerifyUserId < 0) return;
        try {
            authService.resendOtp(pendingVerifyUserId);
            showInfo("Đã gửi lại OTP đến " + email);
        } catch (Exception e) {
            showError("Không thể gửi lại OTP: " + e.getMessage());
        }
    }

    // ── Forgot Password ────────────────────────────────────────────────────────

    @FXML
    private void handleForgotPassword() {
        VBox content = new VBox(16);
        content.setStyle("-fx-padding: 20px; -fx-spacing: 12px;");

        Label title = new Label("? QUÊN MẬT KHẨU");
        title.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 16px; -fx-font-weight: 900; -fx-letter-spacing: 2px;");

        Label header = new Label("Nhập email để khôi phục mật khẩu");
        header.setStyle("-fx-text-fill: #21d9ff; -fx-font-size: 13px; -fx-font-weight: 700;");

        Label infoLabel = new Label("Chúng tôi sẽ gửi link đặt lại mật khẩu đến email của bạn. "
                + "Link sẽ hết hạn trong 30 phút.");
        infoLabel.setWrapText(true);
        infoLabel.setStyle("-fx-text-fill: #8fcddd; -fx-font-size: 12px; -fx-wrap-text: true;");

        Label emailPromptLabel = new Label("Địa chỉ Email:");
        emailPromptLabel.setStyle("-fx-text-fill: #31ff9b; -fx-font-size: 11px; -fx-font-weight: 900; -fx-letter-spacing: 1px;");

        TextField emailField = new TextField();
        emailField.setPromptText("your@email.com");
        emailField.setStyle("-fx-background-color: rgba(3, 16, 25, 0.95); -fx-background-radius: 10; "
                + "-fx-border-radius: 10; -fx-border-width: 1.5; -fx-border-color: rgba(33, 217, 255, 0.35); "
                + "-fx-text-fill: #d7fbff; -fx-prompt-text-fill: rgba(112, 199, 220, 0.5); "
                + "-fx-font-size: 13px; -fx-padding: 12px 14px;");

        content.getChildren().addAll(title, header, infoLabel, emailPromptLabel, emailField);

        Dialog<String> dialog = new Dialog<>();
        dialog.setTitle("Quên mật khẩu");
        dialog.setHeaderText(null);
        dialog.getDialogPane().setStyle("-fx-background-color: linear-gradient(to bottom right, rgba(5, 20, 28, 0.98), rgba(5, 10, 18, 0.98)); "
                + "-fx-border-color: rgba(48, 255, 170, 0.35); -fx-border-radius: 12; -fx-background-radius: 12;");
        dialog.getDialogPane().setContent(content);
        dialog.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);

        Button okButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.OK);
        okButton.setText(" GỬI LINK");
        okButton.setStyle("-fx-background-color: linear-gradient(to right, #31ff9b, #35d5ff); -fx-background-radius: 8; "
                + "-fx-border-radius: 8; -fx-text-fill: #021016; -fx-font-size: 12px; -fx-font-weight: 800; "
                + "-fx-padding: 10px 20px; -fx-cursor: hand;");

        Button cancelButton = (Button) dialog.getDialogPane().lookupButton(ButtonType.CANCEL);
        cancelButton.setText("✕ HUỶ");
        cancelButton.setStyle("-fx-background-color: rgba(255, 76, 122, 0.12); -fx-border-color: rgba(255, 76, 122, 0.55); "
                + "-fx-border-radius: 8; -fx-background-radius: 8; -fx-text-fill: #ff4c7a; -fx-font-size: 12px; "
                + "-fx-font-weight: 800; -fx-padding: 10px 20px; -fx-cursor: hand;");

        okButton.addEventFilter(javafx.event.ActionEvent.ACTION, event -> {
            String email = emailField.getText().trim();
            if (email.isEmpty()) {
                showError("Vui lòng nhập email.");
                event.consume();
            } else if (!email.matches("^[\\w._%+\\-]+@[\\w.\\-]+\\.[a-zA-Z]{2,}$")) {
                showError("Email không hợp lệ.");
                event.consume();
            }
        });

        dialog.setResultConverter(btn -> {
            if (btn == ButtonType.OK) return emailField.getText();
            return null;
        });

        Optional<String> result = dialog.showAndWait();
        result.ifPresent(email -> {
            try {
                ForgotPasswordService forgotService = new ForgotPasswordService();
                forgotService.sendPasswordResetLink(email.trim());
                showInfo("✓ Link đặt lại mật khẩu đã được gửi đến:\n\n" + email.trim() +
                        "\n\nVui lòng kiểm tra hộp thư (kể cả thư rác). Link có hiệu lực trong 30 phút.");
            } catch (IllegalArgumentException e) {
                showError(e.getMessage());
            } catch (Exception e) {
                showError("Không thể gửi link reset. Vui lòng thử lại sau.");
            }
        });
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private void clearLoginFields() {
        if (loginUsernameField  != null) loginUsernameField.clear();
        if (loginPasswordField  != null) loginPasswordField.clear();
        if (rememberMeCheckBox  != null) rememberMeCheckBox.setSelected(false);
    }

    private void clearRegisterFields() {
        if (registerUsernameField     != null) registerUsernameField.clear();
        if (registerDisplayNameField  != null) registerDisplayNameField.clear();
        if (registerEmailField        != null) registerEmailField.clear();
        if (registerPasswordField     != null) registerPasswordField.clear();
        if (registerConfirmPasswordField != null) registerConfirmPasswordField.clear();
    }

    private void setActiveTab(Button active, Button inactive) {
        active.getStyleClass().removeAll("switch-button", "switch-button-active");
        inactive.getStyleClass().removeAll("switch-button", "switch-button-active");
        active.getStyleClass().add("switch-button-active");
        inactive.getStyleClass().add("switch-button");
    }

    private void showError(String message) {
        Alert alert = new Alert(Alert.AlertType.ERROR);
        alert.setHeaderText("Thông báo");
        alert.setContentText(message);
        alert.showAndWait();
    }

    private void showInfo(String message) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION);
        alert.setHeaderText("Thông báo");
        alert.setContentText(message);
        alert.showAndWait();
    }

    private String text(TextField field) {
        return field != null ? field.getText() : null;
    }

    private Stage getStage() {
        return (Stage) formTitle.getScene().getWindow();
    }

    private void reCenterStage() {
        if (formTitle != null && formTitle.getScene() != null) {
            Platform.runLater(() -> {
                Stage stage = getStage();
                stage.sizeToScene();
                stage.centerOnScreen();
            });
        }
    }
}

package minesweeper.repository;

import minesweeper.model.PasswordResetToken;
import minesweeper.repository.exception.DataAccessException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.*;
import java.time.LocalDateTime;

public class PasswordResetRepository {
    private static final Logger LOG = LoggerFactory.getLogger(PasswordResetRepository.class);

    public void save(PasswordResetToken token) throws DataAccessException {
        String sql = "INSERT INTO password_reset_tokens (user_id, token, email, expires_at) " +
                     "VALUES (?, ?, ?, ?)";
        try (Connection conn = DbConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setLong(1, token.getUserId());
            ps.setString(2, token.getToken());
            ps.setString(3, token.getEmail());
            ps.setTimestamp(4, Timestamp.valueOf(token.getExpiresAt()));
            ps.executeUpdate();
        } catch (SQLException e) {
            LOG.error("Failed to save password reset token", e);
            throw new DataAccessException("Lỗi lưu token reset", e);
        }
    }

    public PasswordResetToken findByToken(String token) throws DataAccessException {
        String sql = "SELECT id, user_id, token, email, expires_at, used FROM password_reset_tokens " +
                     "WHERE token = ? AND used = FALSE";
        try (Connection conn = DbConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, token);
            try (ResultSet rs = ps.executeQuery()) {
                if (rs.next()) {
                    PasswordResetToken t = new PasswordResetToken();
                    t.setId(rs.getLong("id"));
                    t.setUserId(rs.getLong("user_id"));
                    t.setToken(rs.getString("token"));
                    t.setEmail(rs.getString("email"));
                    t.setExpiresAt(rs.getTimestamp("expires_at").toLocalDateTime());
                    t.setUsed(rs.getBoolean("used"));
                    return t;
                }
            }
        } catch (SQLException e) {
            LOG.error("Failed to find password reset token", e);
            throw new DataAccessException("Lỗi tìm token reset", e);
        }
        return null;
    }

    public void markUsed(long tokenId) throws DataAccessException {
        String sql = "UPDATE password_reset_tokens SET used = TRUE WHERE id = ?";
        try (Connection conn = DbConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setLong(1, tokenId);
            ps.executeUpdate();
        } catch (SQLException e) {
            LOG.error("Failed to mark token as used", e);
            throw new DataAccessException("Lỗi cập nhật token", e);
        }
    }

    public void deleteExpired() throws DataAccessException {
        String sql = "DELETE FROM password_reset_tokens WHERE expires_at < NOW() OR used = TRUE";
        try (Connection conn = DbConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.executeUpdate();
        } catch (SQLException e) {
            LOG.error("Failed to delete expired tokens", e);
            throw new DataAccessException("Lỗi xóa token cũ", e);
        }
    }
}

package minesweeper.repository;

import minesweeper.model.PasswordResetToken;
import minesweeper.repository.connection.ConnectionFactory;
import minesweeper.repository.connection.ConnectionFactoryProvider;
import minesweeper.repository.exception.DataAccessException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.*;
import java.time.LocalDateTime;
import java.util.Objects;

public class PasswordResetRepository {
    private static final Logger LOG = LoggerFactory.getLogger(PasswordResetRepository.class);

    private static final String SAVE_TOKEN_SQL = 
            "INSERT INTO password_reset_tokens (user_id, token, email, expires_at) VALUES (?, ?, ?, ?)";
    private static final String FIND_TOKEN_SQL = 
            "SELECT id, user_id, token, email, expires_at, used FROM password_reset_tokens WHERE token = ? AND used = FALSE";
    private static final String MARK_USED_SQL = 
            "UPDATE password_reset_tokens SET used = TRUE WHERE id = ?";
    private static final String DELETE_EXPIRED_SQL = 
            "DELETE FROM password_reset_tokens WHERE expires_at < NOW() OR used = TRUE";

    private final ConnectionFactory connectionFactory;

    public PasswordResetRepository() {
        this(ConnectionFactoryProvider.get());
    }

    public PasswordResetRepository(ConnectionFactory connectionFactory) {
        this.connectionFactory = Objects.requireNonNull(connectionFactory, "connectionFactory");
    }

    public void save(PasswordResetToken token) throws DataAccessException {
        try (Connection conn = connectionFactory.getConnection();
             PreparedStatement ps = conn.prepareStatement(SAVE_TOKEN_SQL)) {
            ps.setLong(1, token.getUserId());
            ps.setString(2, token.getToken());
            ps.setString(3, token.getEmail());
            ps.setTimestamp(4, Timestamp.valueOf(token.getExpiresAt()));
            ps.executeUpdate();
            LOG.info("Saved password reset token for userId={}", token.getUserId());
        } catch (SQLException e) {
            LOG.error("Failed to save password reset token", e);
            throw new DataAccessException("Failed to save password reset token", e);
        }
    }

    public PasswordResetToken findByToken(String token) throws DataAccessException {
        try (Connection conn = connectionFactory.getConnection();
             PreparedStatement ps = conn.prepareStatement(FIND_TOKEN_SQL)) {
            ps.setString(1, token);
            try (ResultSet rs = ps.executeQuery()) {
                if (rs.next()) {
                    PasswordResetToken t = new PasswordResetToken();
                    t.setId(rs.getLong("id"));
                    t.setUserId(rs.getLong("user_id"));
                    t.setToken(rs.getString("token"));
                    t.setEmail(rs.getString("email"));
                    t.setExpiresAt(rs.getTimestamp("expires_at").toLocalDateTime());
                    t.setUsed(rs.getBoolean("used"));
                    LOG.debug("Found valid password reset token");
                    return t;
                }
            }
        } catch (SQLException e) {
            LOG.error("Failed to find password reset token", e);
            throw new DataAccessException("Failed to find password reset token", e);
        }
        return null;
    }

    public void markUsed(long tokenId) throws DataAccessException {
        try (Connection conn = connectionFactory.getConnection();
             PreparedStatement ps = conn.prepareStatement(MARK_USED_SQL)) {
            ps.setLong(1, tokenId);
            int rows = ps.executeUpdate();
            if (rows > 0) {
                LOG.info("Marked password reset token as used: tokenId={}", tokenId);
            }
        } catch (SQLException e) {
            LOG.error("Failed to mark token as used", e);
            throw new DataAccessException("Failed to mark token as used", e);
        }
    }

    public void deleteExpired() throws DataAccessException {
        try (Connection conn = connectionFactory.getConnection();
             PreparedStatement ps = conn.prepareStatement(DELETE_EXPIRED_SQL)) {
            int rows = ps.executeUpdate();
            LOG.debug("Deleted {} expired password reset tokens", rows);
        } catch (SQLException e) {
            LOG.error("Failed to delete expired tokens", e);
            throw new DataAccessException("Failed to delete expired tokens", e);
        }
    }
}

CREATE DATABASE IF NOT EXISTS minesweeper_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE minesweeper_db;
CREATE TABLE IF NOT EXISTS users ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, username VARCHAR(100) NOT NULL UNIQUE, display_name VARCHAR(100) NULL, password_hash VARCHAR(255) NULL, email VARCHAR(100) NULL, role ENUM('PLAYER', 'ADMIN') NOT NULL DEFAULT 'PLAYER', is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, last_login_at TIMESTAMP NULL,
KEY idx_username (username) ) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS game_levels ( id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, level_name VARCHAR(50) NOT NULL UNIQUE, rows_count INT UNSIGNED NOT NULL, cols_count INT UNSIGNED NOT NULL, mines_count INT UNSIGNED NOT NULL, sort_order TINYINT UNSIGNED NOT NULL DEFAULT 0, level_type ENUM('PRESET', 'CUSTOM') NOT NULL DEFAULT 'PRESET', created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
KEY idx_level_name (level_name),
CONSTRAINT chk_game_levels_board_size CHECK (rows_count > 0 AND cols_count > 0), CONSTRAINT chk_game_levels_mines_count CHECK (mines_count > 0 AND mines_count < rows_count * cols_count) ) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS game_sessions ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, level_id INT UNSIGNED NOT NULL, result ENUM('WIN', 'LOSE') NOT NULL, completion_time BIGINT UNSIGNED NOT NULL DEFAULT 0, score INT NOT NULL DEFAULT 0, opened_cells INT UNSIGNED NOT NULL DEFAULT 0, flagged_cells INT UNSIGNED NOT NULL DEFAULT 0, started_at TIMESTAMP NULL, first_click_at TIMESTAMP NULL, ended_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
CONSTRAINT fk_game_sessions_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE CASCADE, CONSTRAINT fk_game_sessions_level FOREIGN KEY (level_id) REFERENCES game_levels(id) ON UPDATE CASCADE ON DELETE RESTRICT, CONSTRAINT chk_game_sessions_time CHECK (completion_time >= 0), CONSTRAINT chk_game_sessions_cells CHECK (opened_cells >= 0 AND flagged_cells >= 0), CONSTRAINT chk_game_sessions_datetime CHECK ( first_click_at IS NULL OR ended_at IS NULL OR ended_at >= first_click_at ),
KEY idx_user_result (user_id, result), KEY idx_user_level_created (user_id, level_id, created_at DESC), KEY idx_level_result_time (level_id, result, completion_time ASC), KEY idx_level_score (level_id, score DESC), KEY idx_created (created_at DESC) ) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS player_best_scores ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, level_id INT UNSIGNED NOT NULL, best_time BIGINT UNSIGNED NOT NULL, best_score INT NOT NULL DEFAULT 0, game_session_id BIGINT UNSIGNED NOT NULL, achieved_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT uq_player_best_scores_user_level UNIQUE (user_id, level_id), CONSTRAINT fk_player_best_scores_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE CASCADE, CONSTRAINT fk_player_best_scores_level FOREIGN KEY (level_id) REFERENCES game_levels(id) ON UPDATE CASCADE ON DELETE RESTRICT, CONSTRAINT fk_player_best_scores_session FOREIGN KEY (game_session_id) REFERENCES game_sessions(id) ON UPDATE CASCADE ON DELETE RESTRICT, CONSTRAINT chk_player_best_scores_time CHECK (best_time >= 0),
KEY idx_level_rank (level_id, best_time ASC, best_score DESC, achieved_at ASC) ) ENGINE=InnoDB;
INSERT INTO game_levels (level_name, rows_count, cols_count, mines_count, sort_order, level_type) VALUES ('EASY', 9, 9, 10, 1, 'PRESET'), ('MEDIUM', 16, 16, 40, 2, 'PRESET'), ('HARD', 16, 30, 99, 3, 'PRESET'), ('EXPERT', 20, 30, 145, 4, 'PRESET') ON DUPLICATE KEY UPDATE rows_count = VALUES(rows_count), cols_count = VALUES(cols_count), mines_count = VALUES(mines_count), sort_order = VALUES(sort_order);
-- P15: ranking snapshot table for time-series rank history queries CREATE TABLE IF NOT EXISTS ranking_snapshots ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, level_id INT UNSIGNED NULL, -- NULL = global (cross-level) snapshot rank_position INT UNSIGNED NOT NULL, best_score INT NOT NULL DEFAULT 0, best_time_ms BIGINT UNSIGNED NOT NULL DEFAULT 0, snapshot_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT fk_ranking_snapshots_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE CASCADE, CONSTRAINT fk_ranking_snapshots_level FOREIGN KEY (level_id) REFERENCES game_levels(id) ON UPDATE CASCADE ON DELETE SET NULL,
KEY idx_snapshot_user_level (user_id, level_id, snapshot_at DESC), KEY idx_snapshot_level_at (level_id, snapshot_at DESC) ) ENGINE=InnoDB;
-- P16: audit log for admin actions (deletions, locks, role changes) CREATE TABLE IF NOT EXISTS audit_log ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, admin_id BIGINT UNSIGNED NULL, -- NULL if system-generated action VARCHAR(50) NOT NULL, -- e.g. 'DELETE_SESSION', 'LOCK_USER' target VARCHAR(255) NOT NULL, -- e.g. 'game_sessions:42' details TEXT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT fk_audit_log_admin FOREIGN KEY (admin_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE SET NULL,
KEY idx_audit_created (created_at DESC), KEY idx_audit_action (action) ) ENGINE=InnoDB;

