-- P15: ranking snapshot table for time-series rank history queries CREATE TABLE IF NOT EXISTS ranking_snapshots ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, level_id INT UNSIGNED NULL, -- NULL = global (cross-level) snapshot rank_position INT UNSIGNED NOT NULL, best_score INT NOT NULL DEFAULT 0, best_time_ms BIGINT UNSIGNED NOT NULL DEFAULT 0, snapshot_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT fk_ranking_snapshots_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE CASCADE, CONSTRAINT fk_ranking_snapshots_level FOREIGN KEY (level_id) REFERENCES game_levels(id) ON UPDATE CASCADE ON DELETE SET NULL,
KEY idx_snapshot_user_level (user_id, level_id, snapshot_at DESC), KEY idx_snapshot_level_at (level_id, snapshot_at DESC) ) ENGINE=InnoDB;
-- P16: audit log for admin actions (deletions, locks, role changes) CREATE TABLE IF NOT EXISTS audit_log ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, admin_id BIGINT UNSIGNED NULL, -- NULL if system-generated action VARCHAR(50) NOT NULL, -- e.g. 'DELETE_SESSION', 'LOCK_USER' target VARCHAR(255) NOT NULL, -- e.g. 'game_sessions:42' details TEXT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT fk_audit_log_admin FOREIGN KEY (admin_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE SET NULL,
KEY idx_audit_created (created_at DESC), KEY idx_audit_action (action) ) ENGINE=InnoDB;
-- P17: password reset tokens table CREATE TABLE IF NOT EXISTS password_reset_tokens ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, token VARCHAR(255) NOT NULL UNIQUE, email VARCHAR(255) NOT NULL, expires_at DATETIME NOT NULL, used BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT fk_password_reset_tokens_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE CASCADE,
KEY idx_token (token), KEY idx_user_id (user_id) ) ENGINE=InnoDB;
